// CrawlStream wraps the CrawlEngineHandle.CrawlStream streaming adapter,
// exposing it as a module-level function for test and consumer convenience.
func CrawlStream(engine *CrawlEngineHandle, URL string) (<-chan CrawlEvent, error) {
	req := &CrawlStreamRequest{URL: URL}

	return engine.CrawlStream(*req)
}

// BatchCrawlStream wraps the CrawlEngineHandle.BatchCrawlStream streaming adapter,
// exposing it as a module-level function for test and consumer convenience.
func BatchCrawlStream(engine *CrawlEngineHandle, Urls []string) (<-chan CrawlEvent, error) {
	req := &BatchCrawlStreamRequest{Urls: Urls}

	return engine.BatchCrawlStream(*req)
}

// Validate the configuration, returning an error if any values are invalid.
func (r *CrawlConfig) Validate() error {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.kcrawl_crawl_config_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return fmt.Errorf("failed to create receiver: %s", C.GoString(C.kcrawl_last_error_context()))
	}
	defer C.kcrawl_crawl_config_free(cRecv)
	C.kcrawl_crawl_config_validate(cRecv)
	jsonPtrUpdated := C.kcrawl_crawl_config_to_json(cRecv)
	if jsonPtrUpdated != nil {
		_ = json.Unmarshal([]byte(C.GoString(jsonPtrUpdated)), r)
		C.kcrawl_free_string(jsonPtrUpdated)
	}
	return lastError()
}

// UniqueNormalizedUrls returns the count of unique normalized URLs encountered during crawling.
func (r *CrawlResult) UniqueNormalizedUrls() (uint, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return 0, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.kcrawl_crawl_result_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return 0, fmt.Errorf("failed to create receiver: %s", C.GoString(C.kcrawl_last_error_context()))
	}
	defer C.kcrawl_crawl_result_free(cRecv)
	ptr := C.kcrawl_crawl_result_unique_normalized_urls(cRecv)
	return uint(ptr), nil
}

// CrawlStream stream a single-URL crawl, yielding [`CrawlEvent`]s as pages are processed.
//
// Returns an async stream that emits one event per crawled page, plus a
// terminal `Complete` event. On per-URL failure during the crawl, emits an
// `Error` event followed by `Complete`. The stream item type is wrapped in
// a `Result` to surface transport-level errors; today every emit is `Ok`.
func (h *CrawlEngineHandle) CrawlStream(req CrawlStreamRequest) (<-chan CrawlEvent, error) {
	jsonBytescReq, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescReq) == "null" {
		jsonBytescReq = []byte("{}")
	}
	tmpStrcReq := C.CString(string(jsonBytescReq))
	cReq := C.kcrawl_crawl_stream_request_from_json(tmpStrcReq)
	C.free(unsafe.Pointer(tmpStrcReq))
	if cReq == nil {
		return nil, fmt.Errorf("failed to create crawl_stream_request: %s", C.GoString(C.kcrawl_last_error_context()))
	}
	defer C.kcrawl_crawl_stream_request_free(cReq)

	handle := C.kcrawl_crawl_engine_handle_crawl_stream_start((*C.KCRAWLCrawlEngineHandle)(unsafe.Pointer(h.ptr)), cReq)
	if handle == nil {
		if err := lastError(); err != nil {
			return nil, err
		}
		return nil, fmt.Errorf("failed to start crawl_stream stream")
	}
	ch := make(chan CrawlEvent)
	go func() {
		defer close(ch)
		defer C.kcrawl_crawl_engine_handle_crawl_stream_free(handle)
		for {
			chunkPtr := C.kcrawl_crawl_engine_handle_crawl_stream_next(handle)
			if chunkPtr == nil {
				// Null = clean end-of-stream (errno 0) or stream error (errno != 0).
				// In either case there are no more chunks; close the channel.
				return
			}
			jsonPtr := C.kcrawl_crawl_event_to_json(chunkPtr)
			if jsonPtr == nil {
				C.kcrawl_crawl_event_free(chunkPtr)
				return
			}
			chunk, unmarshalErr := UnmarshalCrawlEvent([]byte(C.GoString(jsonPtr)))
			C.kcrawl_free_string(jsonPtr)
			C.kcrawl_crawl_event_free(chunkPtr)
			if unmarshalErr != nil {
				return
			}
			ch <- chunk
		}
	}()
	return ch, nil
}

